const security = {
  id: 'security',
  title: 'Crypto Security',
  emoji: '🔒',
  color: '#DC2626',
  gradient: ['#991B1B', '#DC2626'],
  description: 'Protect your assets, understand threat models, and build security-first crypto practices.',
  category: 'Core Knowledge',
  modules: [
    {
      id: 'security_beg',
      level: 'beginner',
      title: 'Personal Security Basics',
      emoji: '🛡',
      description: 'Protect your crypto from the most common threats — scams, phishing, and poor key management.',
      color: '#DC2626',
      lessons: [
        { id: 'sec_beg_l1', title: 'Seed Phrase Security', slides: [
          { type: 'intro', title: 'Your Keys, Your Crypto', body: 'The 12 or 24-word seed phrase is the master key to your crypto. Anyone who has it has everything. There is no "forgot password" for crypto. There is no customer service. There is no recovery. The seed phrase is irreplaceable and permanent — treat it accordingly.' },
          { type: 'text', title: 'What a Seed Phrase Controls', body: 'A seed phrase derives every private key in your wallet using a standard (BIP-39). Your ETH address, your BTC address, your Solana address — all derived from the same seed phrase via different derivation paths. Compromise the seed phrase: lose all assets across all chains simultaneously.' },
          { type: 'text', title: 'Storage Best Practices', body: 'Write it on paper (not digital). Better: engrave on metal (Cryptosteel, Bilodeau). Store in a fireproof safe. Never photograph it. Never type it anywhere. Never store it in a password manager, cloud storage, iCloud, Google Drive, or email. Never share it with anyone — no support team, no MetaMask, no legitimate entity will ever ask for your seed phrase.' },
          { type: 'highlight', title: 'The 2-Location Rule', body: 'Store your seed phrase in two geographically separate locations — your home safe AND a bank safety deposit box (or trusted family member\'s location). House fires, floods, and theft are real. A single point of failure for an irreplaceable key is unacceptable risk. Hardware wallet + metal backup in two locations is the minimum professional standard.' },
          { type: 'text', title: 'Hardware Wallets', body: 'Ledger and Trezor are hardware wallets — physical devices that store private keys offline. Even when connected to a compromised computer, the hardware wallet signs transactions on the device without exposing the private key to your computer. For any amount over $1,000, a hardware wallet is not optional. Approximate cost: $50-$200. Insurance premium for your crypto.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Seed phrase = master key. Paper or metal storage only. Two separate geographic locations. Never digital. Never share with anyone. Hardware wallet for any meaningful amount. These five rules prevent the most common catastrophic losses.' },
        ]},
        { id: 'sec_beg_l2', title: 'Phishing and Social Engineering', slides: [
          { type: 'intro', title: 'The Human Attack Vector', body: 'Technical exploits steal millions. But social engineering — tricking humans into giving up access — is more common. The most sophisticated wallet security is useless if you willingly hand your seed phrase to a scammer who told you they were MetaMask support.' },
          { type: 'text', title: 'Common Phishing Attacks', body: 'Discord DMs: "I\'m from the team, I saw you had an issue. Share your screen and I\'ll help." → they watch you type your seed phrase. Fake MetaMask popup: "Your wallet is compromised, enter seed phrase to restore." → never legitimate. Fake Etherscan email: "Unusual activity, verify your wallet at etherscan-wallet.com." → phishing site. Always check URLs character by character.' },
          { type: 'text', title: 'The Fake Support Agent', body: 'The most successful scam in crypto: post a problem in any public Discord or Twitter. Within minutes, fake "support agents" DM you. They are indistinguishable from real team members. No legitimate support team will DM you first, no legitimate support will ask for your seed phrase, and no legitimate support will ask you to visit an external website. Block anyone who does.' },
          { type: 'highlight', title: 'Verification Tactics', body: 'Before interacting with any wallet, DApp, or support channel: Check that the URL matches exactly (bookmark official sites and only use bookmarks). Check for HTTPS and valid SSL certificate. Search "[protocol name] official website" to verify domain. Check the protocol\'s official Twitter for the real domain. Discord: check that the user has a role from the official server. When in doubt, do nothing.' },
          { type: 'text', title: 'SIM Swapping', body: 'SIM swapping: attacker convinces your phone carrier to port your number to their SIM. Now they receive all your 2FA SMS codes. Cryptocurrency investors have lost millions this way. Solution: never use SMS 2FA for crypto accounts. Use hardware keys (YubiKey) or authenticator apps (Google Authenticator, Authy). Contact your carrier to add a PIN or verbal password to prevent port requests.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Social engineering is the #1 attack vector. Legitimate support never DMs first, never asks for seed phrases. Verify every URL character by character. Use authenticator apps, not SMS 2FA. Bookmark official sites and never navigate from email links.' },
        ]},
        { id: 'sec_beg_l3', title: 'Safe Wallet Practices', slides: [
          { type: 'intro', title: 'Separating Risk Profiles', body: 'Professional crypto users separate assets into wallets by risk profile. The same way you don\'t carry $10,000 cash in a wallet you use daily, you shouldn\'t keep your entire portfolio in an active DeFi wallet that interacts with dozens of contracts.' },
          { type: 'text', title: 'The 3-Wallet System', body: 'Cold wallet (hardware): long-term holdings. Never connects to DApps. Never exposed to internet. Warm wallet (software + hardware): medium-term and DeFi. Used for vetted protocols with limited balance. Hot wallet (software only): active trading, new protocol testing, small amounts. Limit exposure by limiting the balance in riskier wallets.' },
          { type: 'text', title: 'Token Approvals: The Hidden Risk', body: 'When you approve a DeFi protocol to spend your tokens, that approval persists indefinitely. If the protocol is exploited 2 years later, unlimited approval contracts can still drain your tokens. Check all approvals at revoke.cash and etherscan.io/tokenapprovalchecker. Revoke approvals for protocols you no longer use. Use exact approval amounts rather than unlimited when possible.' },
          { type: 'highlight', title: 'Transaction Simulation', body: 'Before signing ANY transaction: use Rabby Wallet\'s pre-transaction simulation (shows exactly what will happen — which assets leave, which arrive, which approvals are granted). MetaMask Snaps add similar preview functionality. Never sign transactions where the expected output doesn\'t match what the site told you would happen. Unknown token names in expected outputs = likely drain transaction.' },
          { type: 'text', title: 'The Address Poisoning Attack', body: 'Address poisoning: attacker sends 0-value transactions from an address that looks like one you\'ve transacted with recently. Your transaction history shows similar-looking addresses. If you copy-paste from history instead of your address book, you send to the attacker. Solution: verify last 4+ characters, not just first 4. Save frequently-used addresses in your wallet\'s address book.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: '3-wallet system separates risk. Revoke unused token approvals regularly. Simulate every transaction before signing. Use address books to prevent poisoning attacks. Security is a system of layered habits, not a single action.' },
        ]},
        { id: 'sec_beg_l4', title: 'Exchange Security', slides: [
          { type: 'intro', title: 'When You Don\'t Hold the Keys', body: '"Not your keys, not your crypto" — the crypto security maxim. Centralized exchanges hold your private keys. Exchange hacks, bankruptcies (FTX, Celsius, BlockFi all collapsed in 2022), and regulatory seizures can all prevent access to your funds. Understanding exchange risk is as important as understanding self-custody security.' },
          { type: 'text', title: 'Exchange Hacks History', body: 'Mt. Gox (2014): $450M stolen — 70% of all Bitcoin exchange volume at the time. Bitfinex (2016): $72M stolen. KuCoin (2020): $285M stolen. FTX (2022): $8B+ customer funds disappeared — not a hack, fraud. Binance (2019): $40M stolen. Exchange security has improved but remains an attack target. The lesson: exchanges for active trading, personal custody for storage.' },
          { type: 'text', title: 'Securing Your Exchange Account', body: '2FA: use an authenticator app (Google Authenticator, Authy), NOT SMS. Withdrawal address whitelist: whitelist only your personal wallets. New withdrawal addresses require 24-48 hour cooling period before activation. API key management: disable withdrawal permission on API keys; only enable what\'s needed. Account freeze: most exchanges allow you to call support and freeze your account — have the number saved.' },
          { type: 'highlight', title: 'How Much to Keep on Exchange', body: 'Keep only what you need for active trading on any exchange. Rule of thumb: never more than 5% of portfolio on a single exchange. Even Binance (the world\'s largest) had a $40M hack and faced regulatory issues. FTX, once the 2nd largest, was fraud from day 1. Diversify across 2-3 exchanges at most, and keep the rest in self-custody.' },
          { type: 'text', title: 'Proof of Reserves', body: 'Post-FTX, legitimate exchanges publish monthly Proof of Reserves (PoR) — cryptographic proof that customer assets are held 1:1 on-chain. Kraken, Coinbase, OKX all publish PoR. Check your exchange\'s PoR status. An exchange refusing to publish PoR is a red flag. Nansen.ai and Arkham track exchange wallet balances in real-time — public on-chain transparency for custodial funds.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Exchanges are attack targets — FTX proved fraud is possible too. Use authenticator 2FA. Whitelist withdrawal addresses. Keep only active trading funds on exchange (max 5% per exchange). Check Proof of Reserves monthly. Self-custody the rest.' },
        ]},
        { id: 'sec_beg_l5', title: 'Recovery Planning', slides: [
          { type: 'intro', title: 'Planning for the Unplannable', body: 'Crypto security isn\'t just protecting against attackers — it\'s protecting against accidents: lost devices, forgotten passwords, unexpected death, or incapacitation. Your heir needs to access your crypto. Your future self after a disaster needs to access your crypto. Plan for this now.' },
          { type: 'text', title: 'The Seed Phrase Inheritance Problem', body: 'You die tomorrow. Your spouse knows you hold $500k in crypto. They don\'t know what a seed phrase is. They can\'t find it. The crypto is permanently inaccessible. This is one of the most common forms of crypto loss and it\'s entirely preventable with preparation. Estate planning for crypto requires the same rigor as planning for physical assets.' },
          { type: 'text', title: 'The Crypto Estate Plan', body: 'Write a "crypto will": where seed phrases are stored, how to access them, what wallets/exchanges exist, how to convert to fiat if needed. Store with your physical estate documents or give to a trusted attorney. Consider a dead man\'s switch service (Casa, Unchained Capital) that provides backup access after verified death. The crypto estate plan is one document that prevents enormous loss.' },
          { type: 'highlight', title: 'Shamir\'s Secret Sharing', body: 'Shamir\'s Secret Sharing (SSS) splits a seed phrase into N shares where any M shares can reconstruct it (e.g., 3-of-5). Give one share to each of 5 trusted people. Any 3 can recover your wallet. No single person has enough to steal. None know what the others hold. Trezor and Unchained Capital implement SSS. This is the highest security for meaningful amounts.' },
          { type: 'text', title: 'Multi-Sig for Inheritance', body: 'Multi-signature wallets (2-of-3 or 3-of-5) require multiple key holders to sign transactions. For inheritance: you hold 2 keys, your estate attorney holds 1. If you die, attorney + executor can reconstruct access. Services like Casa and Unchained Capital specialize in multi-sig for Bitcoin holders. The setup cost is justified for any meaningful holding.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'Crypto estate planning is as important as security against attackers. Write a crypto will. Shamir\'s Secret Sharing distributes access securely across trusted parties. Multi-sig enables inheritance without exposing full key access. Plan now — you cannot recover after the fact.' },
        ]},
      ],
      quiz: [
        { id: 'sec_beg_q1', question: 'Why should seed phrases never be stored digitally (photos, cloud storage, email)?', options: ['Digital storage is unreliable and may get deleted', 'Digital storage is accessible to hackers — cloud accounts, email, and photo libraries are all compromised in large-scale breaches. A digital copy of your seed phrase makes it as vulnerable as any password', 'Seed phrases are too long for digital formats', 'Blockchain nodes monitor digital storage for seed phrases'], correct: 1, explanation: 'Photos go to iCloud, screenshots sync to Google Photos, emails can be breached. Any digital storage is vulnerable to: cloud account compromise, device seizure, backup exposure, and large-scale data breaches. A seed phrase on paper in a safe has never been hacked remotely. Security through physical isolation is fundamentally different from digital security.' },
        { id: 'sec_beg_q2', question: 'What is a SIM swap attack and how do you prevent it?', options: ['Hackers clone your crypto hardware wallet', 'An attacker convinces your phone carrier to port your number to their SIM, gaining access to SMS 2FA codes. Prevention: use authenticator apps or hardware keys instead of SMS 2FA', 'Malware that intercepts crypto transactions on your SIM card', 'A physical theft of your phone to access exchanges'], correct: 1, explanation: 'Telecom employees can be bribed or tricked into porting your number. Once the attacker has your number, they receive all SMS 2FA codes — gaining access to every account using SMS authentication. Prevention: never use SMS 2FA for crypto, use Google Authenticator or Authy, and ask your carrier to add a port block PIN.' },
        { id: 'sec_beg_q3', question: 'What is address poisoning and how do you protect against it?', options: ['Hackers sending infected tokens to your wallet', 'Attacker sends 0-value transactions from addresses similar to your frequent contacts. If you copy an address from transaction history, you may send to the attacker. Prevention: use address book, verify last 4+ characters', 'Corrupting a wallet\'s address derivation algorithm', 'Injecting malicious code into a smart contract address'], correct: 1, explanation: 'Address poisoning exploits lazy address verification. Attackers send $0 transactions from addresses where first 4 and last 4 characters match a known sender. You copy from history instead of your address book — and send to the attacker. Always verify the full middle section of addresses, or use a trusted address book.' },
        { id: 'sec_beg_q4', question: 'What is Proof of Reserves (PoR) and why does it matter post-FTX?', options: ['An exchange\'s investor documentation', 'Cryptographic proof that an exchange holds customer assets 1:1 on-chain — verifiable without trusting the exchange\'s own accounting. FTX proved that customer-reported balances could be lies', 'A tax reporting requirement for exchanges', 'A smart contract auditing standard'], correct: 1, explanation: 'FTX claimed to hold customer funds but didn\'t. PoR uses cryptographic proofs (Merkle trees) to prove on-chain that assets held ≥ liabilities claimed. Any exchange with nothing to hide publishes PoR. An exchange refusing to publish PoR should be treated with suspicion. Verify on nansen.ai or the exchange\'s own PoR dashboard.' },
        { id: 'sec_beg_q5', question: 'What is Shamir\'s Secret Sharing and how does it help with crypto inheritance?', options: ['A type of multi-signature wallet requiring bank approval', 'A cryptographic method that splits a seed phrase into N shares where any M shares reconstruct it — distributing pieces to trusted people so no single person has full access but multiple can recover together', 'A legal trust structure for crypto assets', 'A key derivation algorithm used in BIP-39'], correct: 1, explanation: '3-of-5 SSS: split seed phrase into 5 shares. Any 3 reconstruct it. Give to 5 trusted people. No single person can steal it (need 3 to collude). Any 3 survivors can recover after your death. Trezor\'s Shamir Backup implements this natively. For meaningful crypto holdings, SSS is the most secure inheritance and recovery solution.' },
      ],
    },
    {
      id: 'security_int',
      level: 'intermediate',
      title: 'DeFi Security',
      emoji: '⚔️',
      description: 'Evaluate protocol risk, spot exploits before they happen, and navigate DeFi safely.',
      color: '#DC2626',
      lessons: [
        { id: 'sec_int_l1', title: 'Protocol Risk Assessment', slides: [
          { type: 'intro', title: 'Evaluating Before Depositing', body: 'Every DeFi protocol carries risk. The question isn\'t whether risk exists — it\'s whether the yield compensates for the risk. Professional DeFi participants have a systematic framework for evaluating protocols before depositing meaningful capital.' },
          { type: 'text', title: 'The Audit Stack', body: 'Minimum bar for consideration: 1 major audit from a reputable firm. Reputable auditors: Trail of Bits, OpenZeppelin, Spearbit, Certora, Sherlock, Code4rena finalists. Not all audits are equal: a $5,000 audit from an unknown firm is not the same as a $200,000 audit from Trail of Bits. Check: how many audits, who did them, were findings fixed, what remained unresolved.' },
          { type: 'text', title: 'TVL and Time as Proxies', body: 'A protocol with $500M TVL that has operated for 2+ years without exploit is strong evidence of security. Not proof — but evidence. The longer a high-TVL contract operates without being drained, the more confidence you can have. New protocols with no track record and high APY are the highest risk. Be suspicious of protocols that launched in the last 6 months offering 100%+ APY.' },
          { type: 'highlight', title: 'DeFiLlama Hacks Database', body: 'DeFiLlama maintains a complete database of every significant DeFi exploit. Filter by protocol type, chain, and attack vector. Before depositing in ANY protocol, search its name in the hacks database. Check if it\'s been exploited before. If so: was the vulnerability fixed? Was full restitution made? Did the team respond credibly? Prior exploit + strong recovery > never exploited + no security investment.' },
          { type: 'text', title: 'Admin Key Risk', body: 'Who can upgrade the contract? Who controls admin functions? Check: is there a timelock (delays upgrades, giving users time to exit)? Is there a multi-sig (multiple parties must agree to upgrade)? Is there no upgrade capability at all (fully immutable)? Immutable with no admin keys = most secure but can\'t fix bugs. Multisig + timelock = pragmatic balance. Single EOA admin key = run away.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Evaluate audits (who, how many, findings fixed). TVL + time are imperfect but meaningful proxies. Check DeFiLlama\'s hacks database. Assess admin key risk: timelock + multisig is the minimum standard. Systematic evaluation beats vibes-based FOMO.' },
        ]},
        { id: 'sec_int_l2', title: 'Common DeFi Attack Patterns', slides: [
          { type: 'intro', title: 'The Recurring Playbook', body: '$5B+ in DeFi exploits have followed recognizable patterns. Most attacks are not novel — they\'re variations of known vulnerabilities applied to new code. Learning these patterns lets you evaluate protocols critically and recognize warning signs before you\'ve deposited.' },
          { type: 'text', title: 'Flash Loan Attacks', body: 'Pattern: flash borrow massive capital → manipulate on-chain prices → exploit protocols that trust those prices → repay loan. Cream Finance ($130M) attacked via flash loan price manipulation. Value DeFi ($6M). Pancake Bunny ($45M). The attack is enabled by single-block oracle reliance. Safe protocols use TWAP (Time-Weighted Average Price) oracles that smooth out single-block manipulation.' },
          { type: 'text', title: 'Rug Pulls', body: 'Rug pull: developers drain liquidity and abandon the project. Patterns: anonymous team + rapid token launch. No code audit. Marketing emphasizes returns, not technology. Liquidity not locked. Admin keys not renounced. Vesting: team tokens immediately liquid. Tool: RugDoc.io analyzes contract code for rug pull indicators. Honeypot check: attempt to sell a small amount before buying any meaningful position.' },
          { type: 'highlight', title: 'Bridge Exploits', body: 'Cross-chain bridges hold $billions and have been the largest hack targets: Ronin ($625M), Wormhole ($320M), Nomad ($190M). Common vectors: validator key compromise (Ronin: 5 of 9 Ronin validators compromised), signature validation bugs (Nomad: invalid messages accepted as valid), unlimited minting bugs. Always use canonical bridges for large amounts and monitor bridge security reports.' },
          { type: 'text', title: 'Governance Attacks', body: 'Beanstalk ($182M, 2022): flash loan governance. Build Finance: community assumed they owned all admin keys; one key holder drained treasury unilaterally. Tornado Cash: governance attack by malicious proposal granting attacker 1,200,000 TORN. Defense: timelocks on governance execution, quorum requirements, vote-escrowed governance tokens (can\'t flash-loan locked tokens).' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Flash loans enable oracle manipulation. Rug pulls follow predictable patterns (anon team, unlocked liquidity, no audit). Bridge exploits reflect validator key risk or validation logic bugs. Governance attacks require timelocks and vote-escrowing. Know the playbook to see it coming.' },
        ]},
        { id: 'sec_int_l3', title: 'Scam Detection', slides: [
          { type: 'intro', title: 'The Scam Ecosystem', body: 'Crypto scams stole $3.8B in 2023 (Chainalysis). The ecosystem of pig-butchering scams, fake investment platforms, romance fraud, and impersonation is sophisticated and growing. Understanding the playbooks removes the emotional manipulation that makes them effective.' },
          { type: 'text', title: 'Pig Butchering', body: 'The most sophisticated crypto scam: build a relationship with target (often via dating apps or random texts). Develop trust over weeks. "Accidentally" reveal crypto profits. Offer to show the target how. Guide them to a fake exchange that shows manipulated profits. Target deposits more and more. When they try to withdraw: "tax required first," "minimum balance required." Site disappears. Estimated $75B+ globally.' },
          { type: 'text', title: 'The Guaranteed Return Red Flag', body: 'No legitimate investment offers guaranteed returns. "15% monthly guaranteed" = scam. Bitconnect promised this — stole $1B before collapsing. OneCoin: promised 50%+ returns — stole $4B. HyperFund, JuicyFields, and hundreds of others. If return is "guaranteed" and "risk-free" in any investment, it is definitionally fraud. Real yield has risk. Guaranteed yield is a lie.' },
          { type: 'highlight', title: 'Fake Token Scams', body: '"You have 100,000 USDC in your wallet but can\'t withdraw until you pay 0.1 ETH in fees." The USDC was manufactured — it\'s a fake token with a custom name that looks like USDC in your wallet. You send real ETH "to pay fees." The fake USDC is worthless. How to check: verify contract address matches the real USDC on Etherscan. Never pay gas to release "stuck" funds from unknown sources.' },
          { type: 'text', title: 'Celebrity Endorsement Scams', body: '"Elon Musk is giving away 5,000 BTC! Send 0.5 BTC to get 1 BTC back." This has never been real. Elon Musk has never given away crypto. Neither has Vitalik Buterin, Changpeng Zhao, or any other crypto celebrity. Deep fake videos of celebrities promoting crypto on YouTube are increasingly convincing. The rule: celebrity giving away crypto = 100% scam. No exceptions. Ever.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Pig butchering uses relationship building to extract crypto from victims. Guaranteed returns are definitionally fraud. Fake tokens use custom contract names to look like real assets. Celebrity giveaways are always scams. Pattern recognition removes the emotional manipulation.' },
        ]},
        { id: 'sec_int_l4', title: 'Operational Security (OpSec)', slides: [
          { type: 'intro', title: 'The Information You Leak', body: 'OpSec (Operational Security) is about controlling what information adversaries can use against you. Crypto has unique OpSec requirements — your on-chain address is permanently public, and anything you associate with it (social media, KYC records) becomes public too.' },
          { type: 'text', title: 'Address Privacy', body: 'Every transaction from your wallet is public. If you KYC on Coinbase with your address, Coinbase knows everything you\'ve done on-chain. If you post your ENS on Twitter, everyone knows your holdings. Privacy tools: use fresh addresses for each protocol relationship. Tornado Cash (now sanctioned in US) was the mixing solution. Railgun is the current privacy-preserving alternative. For privacy, never reuse addresses.' },
          { type: 'text', title: 'Social Media OpSec', body: 'Don\'t publicly post: how much crypto you hold. What exchange you use. That you hold crypto at all. If you must post: use abstract amounts ("a significant position") not specific numbers. Announcing your holdings publicly makes you a target for sophisticated phishing attacks, SIM swaps, and in extreme cases, the $5 wrench attack.' },
          { type: 'highlight', title: 'The $5 Wrench Attack', body: 'Physical coercion: "Tell me your seed phrase or I hurt you." Security systems that protect against remote hackers don\'t protect against someone who knows you have crypto and threatens you physically. Mitigations: hold most holdings in cold storage with distributed keys (attacker can\'t access without multiple parties), maintain a "decoy wallet" with small amount that looks plausible, avoid public association of your identity with your crypto holdings.' },
          { type: 'text', title: 'Device Security', body: 'Dedicated device for crypto: a laptop used ONLY for crypto transactions, no other browsing, no email, no social media. Reduces malware exposure to near-zero. Use-specific browsers: Brave for crypto, separate profile for everything else. Hardware 2FA (YubiKey) for all accounts. Full disk encryption. Enable remote wipe. Keep OS and software current. These habits compound into significant malware resistance.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Your on-chain address is permanently public — manage what you associate with it. Never publicly disclose crypto holdings or amounts. The $5 wrench attack is real for known holders. A dedicated crypto device dramatically reduces malware attack surface.' },
        ]},
        { id: 'sec_int_l5', title: 'Recovery After Compromise', slides: [
          { type: 'intro', title: 'When Bad Things Happen', body: 'Despite best practices, compromises happen. Understanding how to respond immediately — within minutes — determines how much you can recover. Speed is critical because attackers typically drain wallets immediately upon gaining access.' },
          { type: 'text', title: 'The Emergency Response Playbook', body: 'Step 1 (0-5 minutes): Generate a new wallet on a fresh device. Step 2 (5-15 minutes): Transfer all remaining assets to the new wallet using "sweeper" tools if the attacker has your private key. Step 3 (15 min): Revoke all approvals on the compromised wallet (revoke.cash). Step 4: Change all passwords + 2FA on associated exchange accounts. Step 5: Identify how the compromise happened.' },
          { type: 'text', title: 'The Gas Problem in Compromises', body: 'If an attacker has your private key but not your ETH for gas, you can potentially recover your ERC-20 tokens. The challenge: sending ETH to pay gas for the transfer also gets swept by the attacker\'s bot. Solutions: Flashbots Protect bundles (send ETH + transfer ERC20 in same block, attacker can\'t front-run). OpenZeppelin Defender automated rescue scripts. Speed matters — bots can respond in milliseconds.' },
          { type: 'highlight', title: 'What Is NOT Recoverable', body: 'Tokens sent to wrong address: not recoverable. ETH sent to smart contracts that don\'t accept it: not recoverable. NFTs burned: not recoverable. Tokens sent to 0x0 (burn address): not recoverable. Transactions on blockchain: permanent. This is why simulation and double-checking before every significant transaction is not optional. Blockchain permanence means mistakes are permanent.' },
          { type: 'text', title: 'Reporting and Resources', body: 'Report exploits: Chainalysis provides free blockchain analysis for law enforcement. FBI IC3.gov tracks crypto fraud. Interpol has crypto cybercrime units. Recovery: difficult but not impossible for large amounts. Binance has frozen hacked funds. Several exchanges cooperate with law enforcement to freeze stolen assets. Post-mortem: understand exactly how the compromise happened — prevent recurrence.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'Emergency response: new wallet, asset sweep, approval revocation within 15 minutes. Use Flashbots Protect for gas-front-run resistance during recovery. Some losses are permanently irreversible — prevention is everything. Report to FBI IC3 and Chainalysis for large compromises.' },
        ]},
      ],
      quiz: [
        { id: 'sec_int_q1', question: 'Why do TWAP (Time-Weighted Average Price) oracles resist flash loan attacks?', options: ['TWAP uses off-chain price data that can\'t be manipulated', 'TWAP averages price over multiple blocks — a flash loan can only manipulate price within a single block, not the historical average that TWAP reflects', 'TWAP requires multiple oracle providers to agree', 'TWAP is more expensive to compute, deterring attackers'], correct: 1, explanation: 'Flash loans exist within a single transaction (one block). TWAP averages price over 30+ minutes of blocks. Manipulating a TWAP oracle requires maintaining price manipulation across many blocks — astronomically expensive and impractical. Spot price oracles that read current pool price are vulnerable to flash loans; TWAP oracles are not.' },
        { id: 'sec_int_q2', question: 'What is a "rug pull" and what are the warning signs?', options: ['A smart contract vulnerability where funds get trapped', 'Developers drain liquidity and abandon the project. Warning signs: anonymous team, no audit, unlocked liquidity, immediately liquid team tokens, returns-focused marketing with no technical substance', 'A governance attack where malicious proposals drain the treasury', 'When whales simultaneously sell to crash price'], correct: 1, explanation: 'Rug pull warning signs: anonymous/unverifiable team, no reputable audit, liquidity not locked or time-locked, team tokens with no vesting, no smart contract verification on Etherscan, marketing emphasizing returns over technology. Use RugDoc.io and attempt to sell a small test amount before any significant purchase.' },
        { id: 'sec_int_q3', question: 'What is pig-butchering and why is it so effective?', options: ['A type of smart contract exploit', 'A long-duration relationship scam: build trust with target over weeks via dating apps or random contact, guide them to fake crypto platforms, maximize deposits before disappearing — estimated $75B+ globally', 'A flash loan attack on lending protocols', 'A market manipulation strategy using large sell orders'], correct: 1, explanation: 'Pig butchering (from "fattening the pig before slaughter"): build a genuine emotional relationship with the target, introduce "amazing" crypto returns you\'re making, guide them to a fake exchange that shows fabricated profits, encourage increasing deposits, then steal everything. The relationship manipulation makes victims reluctant to believe they\'re being scammed even as it happens.' },
        { id: 'sec_int_q4', question: 'How do fake token scams work?', options: ['By creating identical contract addresses through hash collisions', 'Deploying a custom ERC-20 token with a name/symbol matching a real asset (like USDC). Victim sees "100,000 USDC" in wallet but can\'t withdraw until paying ETH "fees" — the USDC is worthless; the ETH fee is real', 'By exploiting a vulnerability in MetaMask\'s token display', 'By manipulating token prices through large trades'], correct: 1, explanation: 'Anyone can deploy an ERC-20 named "USD Coin" with symbol "USDC." Your wallet shows the fake name, not the contract address. The scam: you "receive" fake USDC, try to withdraw but are told you need ETH to pay release fees — you send real ETH, the fake USDC remains worthless. Always verify token contract addresses against the real token\'s official contract.' },
        { id: 'sec_int_q5', question: 'What is the "Flashbots Protect" solution to the gas problem in wallet compromises?', options: ['A way to recover lost private keys', 'Bundling the "send ETH" transaction and the "transfer tokens" transaction in a single block so attackers can\'t front-run the ETH arrival and sweep it before you can execute your recovery transfer', 'A multi-sig wallet for emergency recovery', 'A legal tool to freeze compromised wallet transactions'], correct: 1, explanation: 'When attackers have your private key, their bots watch for incoming ETH and sweep it immediately (before you can use it for gas). Flashbots Protect bundles your ETH funding + token transfer in a single block — they arrive and execute atomically, leaving no window for the attacker\'s bot to intercept the ETH.' },
      ],
    },
    {
      id: 'security_exp',
      level: 'expert',
      title: 'Protocol Security Engineering',
      emoji: '🔬',
      description: 'Design secure systems, run bug bounties, and build institutional-grade security programs.',
      color: '#DC2626',
      lessons: [
        { id: 'sec_exp_l1', title: 'Security Architecture', slides: [
          { type: 'intro', title: 'Security by Design', body: 'Retrofitting security onto an insecure system is expensive, incomplete, and often impossible. Security-first design means considering threat models, trust boundaries, and attack surfaces during initial architecture — before a single line of code is written.' },
          { type: 'text', title: 'Threat Modeling', body: 'Systematic threat modeling: identify assets (what\'s valuable). Identify threat actors (who wants to steal/disrupt it). Identify attack vectors (how could they reach it). Assess likelihood and impact for each threat. Prioritize mitigations accordingly. STRIDE framework: Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, Elevation of Privilege — applied to each system component.' },
          { type: 'text', title: 'Defense in Depth', body: 'No single security control is sufficient. Layer multiple independent controls: smart contract access controls + multisig + timelock + circuit breakers + off-chain monitoring + insurance. Each layer addresses different attack vectors and failure modes. The attacker must defeat every layer simultaneously — multiplicative security vs. additive vulnerability.' },
          { type: 'highlight', title: 'Invariant Design', body: 'Define protocol invariants upfront: "total supply always equals sum of all balances." "Collateralization ratio always > 150%." "Only the authorized bridge can mint wrapped tokens." These invariants must hold regardless of what sequence of transactions is executed. Write them first. Then write code that enforces them. Then verify with formal methods and fuzzing.' },
          { type: 'text', title: 'Emergency Preparedness', body: 'Before launch, design and test your emergency response: guardian multisig with authority to pause. Monitoring scripts that detect anomalous behavior in real-time. Communication templates for different scenarios (exploit, bug, regulatory). Recovery plan for different exploit types. Practice the emergency response before mainnet — incident response under live attack pressure is too late to plan.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Security-first design uses threat modeling before coding. Defense in depth layers multiple independent controls. Invariants are defined first and enforced throughout. Emergency preparedness requires planning and practice before mainnet.' },
        ]},
        { id: 'sec_exp_l2', title: 'Bug Bounty Programs', slides: [
          { type: 'intro', title: 'Paying for Security', body: 'Bug bounty programs create economic incentives for white-hat hackers to find and report vulnerabilities rather than exploit them. A $1M bounty for a critical vulnerability is significantly cheaper than the $100M exploit that would have occurred without it.' },
          { type: 'text', title: 'Immunefi: The Standard', body: 'Immunefi is the largest Web3 bug bounty platform with $100M+ in bounties paid. Bounty tiers: Critical (smart contract drain) $10k-$10M. High (significant fund loss risk) $5k-$100k. Medium (limited impact) $1k-$10k. Low (informational) $100-$1k. Immunefi validates reports, adjudicates disputes, and ensures payment. Submit your protocol\'s bounty program here.' },
          { type: 'text', title: 'Bounty Scope Design', body: 'Well-defined scope: exactly which contracts are in scope, which are excluded. Asset scope: what assets are at risk. Out of scope: test contracts, deprecated contracts, third-party integrations. Report requirements: proof-of-concept, estimated impact, responsible disclosure timeline. Vague scope creates disputes; precise scope enables quality reports and fair adjudication.' },
          { type: 'highlight', title: 'Responsible Disclosure', body: 'White-hat ethical standard: report privately to the team before public disclosure. Standard timeline: 48-90 days for fixes, then public disclosure. The hacker earns the bounty; the team patches before attackers know about the vulnerability. MakerDAO and Compound both paid $1M+ bounties for critical findings. The trust between white hats and protocols is the foundation of the bounty ecosystem.' },
          { type: 'text', title: 'Continuous Audit Programs', body: 'Beyond point-in-time audits: Sherlock and Code4rena offer continuous "contest" audits where security researchers continuously review your protocol for a monthly fee. Wardens (researchers) earn rewards for finding issues. The protocol gets ongoing security coverage. More expensive than one-time audits but appropriate for high-TVL protocols making regular code changes.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Bug bounties economically align white-hats with protocol security. Immunefi is the standard platform. Precise scope reduces disputes. Responsible disclosure builds ecosystem trust. Continuous audit programs provide ongoing coverage for evolving protocols.' },
        ]},
        { id: 'sec_exp_l3', title: 'Incident Response', slides: [
          { type: 'intro', title: 'When an Exploit Happens', body: 'An exploit notification arrives at 3am. $50M is being drained. How you respond in the next 30 minutes determines whether it becomes a $50M loss or a $500M loss. Incident response is a skill that must be prepared and practiced before you need it.' },
          { type: 'text', title: 'The First 15 Minutes', body: 'Alert the full team immediately. Pause the protocol if possible. Identify the exploit vector (requires understanding your contracts deeply). Estimate total exposure. Assign roles: technical (understand/stop exploit), communications (prepare statement), legal (evaluate obligations), treasury (assess resources). Begin on-chain monitoring of the attacker\'s wallet.' },
          { type: 'text', title: 'Communication During Crisis', body: 'Post a Twitter/X acknowledgment immediately even with minimal information: "We\'re investigating reports of an issue with [protocol]. Please do not deposit. We will update in 30 minutes." Silence is interpreted as abandonment. Update every 30 minutes with whatever you know. Never speculate about cause or amount before confirmed. Transparency builds trust; silence destroys it.' },
          { type: 'highlight', title: 'White-Hat Recovery', body: 'Some protocols negotiate with attackers post-exploit. Contact on-chain (send a transaction with a message to the attacker\'s address). Offer: keep 10-15% as a "bug bounty," return 85-90%, no legal pursuit. The Euler Finance hacker returned ~$177M after on-chain negotiation. Poly Network hacker returned $610M. White-hat resolution is possible when the attacker fears legal consequences or has a conscience.' },
          { type: 'text', title: 'Post-Exploit Recovery', body: 'After the immediate crisis: full post-mortem (how did this happen, what failed in the security stack). Restitution plan (how will affected users be compensated — own protocol funds, insurance, emergency fundraise). Code patch + enhanced audit. Gradual relaunch with deposit limits. Transparency about what changed. Most protocols that survive exploits with transparent handling emerge with community trust intact.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: '15-minute response: pause protocol, alert team, identify vector, assign roles. Communication every 30 minutes prevents abandonment perception. White-hat negotiation can recover majority of funds. Post-mortem + restitution plan + transparent relaunch rebuilds trust.' },
        ]},
        { id: 'sec_exp_l4', title: 'Institutional Security', slides: [
          { type: 'intro', title: 'Enterprise Crypto Security', body: 'As crypto matures, institutional participants — hedge funds, family offices, corporate treasuries — hold billions in digital assets. The security requirements are dramatically different from individual holders: multi-party approvals, custodian relationships, regulatory compliance, and audit trails.' },
          { type: 'text', title: 'Qualified Custodians', body: 'SEC regulations require investment advisors holding client crypto to use qualified custodians (US). Approved custodians: Coinbase Custody (holds $200B+), BitGo, Anchorage Digital (OCC charter), Fidelity Digital Assets, and others. Features: segregated accounts, $100M+ insurance, SOC2 Type II certification, direct clearing relationships, and full audit trails meeting financial reporting requirements.' },
          { type: 'text', title: 'Multi-Party Computation (MPC)', body: 'MPC wallets (Fireblocks, Fordefi, Qredo) split private keys into shares distributed across multiple parties and devices. No single party ever holds the complete key. Transactions require threshold approval (e.g., 3-of-5 approvers). The key is never reconstructed in any single device. This eliminates the "key theft" attack vector while enabling institutional-grade workflow automation.' },
          { type: 'highlight', title: 'Policy-Based Approvals', body: 'Enterprise MPC platforms support: transaction limits ($50k auto-approve, $500k requires 2 approvers, $5M requires board vote). Whitelist-only destinations. Scheduled time windows for transfers. Geographic restrictions. Business justification requirements for large amounts. Automatic blocking of unwhitelisted contracts. These controls match enterprise treasury management requirements.' },
          { type: 'text', title: 'Regulatory Compliance Framework', body: 'NYDFS BitLicense, EU MiCA framework, UK FCA registration — each jurisdiction has different requirements. Common requirements: transaction monitoring for AML. KYC on all counterparties. Sanctions screening (OFAC compliance). Record retention (7 years in US). Travel Rule compliance for transfers. Incident reporting to regulators. Building regulatory compliance from day 1 is dramatically cheaper than retrofitting it.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Institutional security requires qualified custodians (Coinbase Custody, BitGo), MPC wallets (Fireblocks), and policy-based approvals matching enterprise treasury controls. Regulatory compliance (AML, KYC, sanctions) must be built in from day 1 — retrofitting is prohibitively expensive.' },
        ]},
        { id: 'sec_exp_l5', title: 'The Security Researcher Career', slides: [
          { type: 'intro', title: 'Security Research as a Career', body: 'Smart contract security research is one of the highest-paying technical careers in crypto. Top researchers at audit firms earn $200k-$500k/year. Independent security researchers on Immunefi have earned $5M+ from a single critical vulnerability discovery. This lesson maps the career path.' },
          { type: 'text', title: 'Skills Required', body: 'Deep Solidity knowledge: can read and understand any smart contract. Attack playbook: knows every known vulnerability class cold. EVM internals: understands opcodes, gas mechanics, storage layout. DeFi protocol knowledge: understands how AMMs, lending, stablecoins, and oracles work mechanically. Formal verification: Certora CVL or Halmos. Testing: Foundry fuzzing, invariant testing. Mathematical reasoning for complex protocols.' },
          { type: 'text', title: 'The Practice Path', slides: [], body: 'Learning progression: Ethernaut (OpenZeppelin) → basic Solidity security. Damn Vulnerable DeFi → complex DeFi protocol attacks. OpenZeppelin CTF → intermediate. Paradigm CTF → advanced. Curta → community puzzles. Each CTF category requires different skills. Time investment: 6-12 months of serious practice to be competitive in public audits.' },
          { type: 'highlight', title: 'The Competitive Audit Circuit', body: 'Code4rena, Sherlock, Cantina: competitive audits where researchers race to find bugs in exchange for prizes. Top researchers earn $300k-$1M+/year from the circuit alone. The circuit builds your reputation through verified, public findings. A profile with 20+ high/critical findings on Code4rena is a credential that top audit firms actively recruit from.' },
          { type: 'text', title: 'Joining Audit Firms', body: 'Top firms: Trail of Bits, OpenZeppelin, Spearbit, Cyfrin, Sherlock, Code4rena\'s team. They hire from: competitive audit top performers, academic cryptography/security backgrounds, and exceptional CTF players. The typical path: competitive audit portfolio → contract with a firm → full-time hire. Compensation: $150k-$400k base + token grants for senior positions at top firms.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'Security research is one of crypto\'s highest-paid technical paths. Skills: deep Solidity, attack taxonomy, EVM internals, DeFi mechanics. Practice via Ethernaut, Damn Vulnerable DeFi, Paradigm CTF. Build portfolio on Code4rena/Sherlock. Firms recruit directly from competitive audit rankings.' },
        ]},
      ],
      quiz: [
        { id: 'sec_exp_q1', question: 'What is the STRIDE threat modeling framework?', options: ['A smart contract testing methodology', 'A systematic framework for identifying threats across 6 categories: Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, Elevation of Privilege — applied to each system component', 'A code review checklist for Solidity contracts', 'A regulatory compliance framework for crypto protocols'], correct: 1, explanation: 'STRIDE helps systematically enumerate threats. For each system component: Can identity be spoofed? Can data be tampered? Can actions be repudiated? Is sensitive data disclosed? Can service be denied? Can privileges be escalated? Applying STRIDE to every component ensures comprehensive threat coverage before writing code.' },
        { id: 'sec_exp_q2', question: 'Why are Immunefi bug bounties economically rational even at $1M+ for critical findings?', options: ['Immunefi subsidizes bounty costs for protocols', 'A $1M bounty for a critical vulnerability is far cheaper than the $10M-$500M exploit that would have occurred without the responsible disclosure — the bounty creates financial incentive for white-hats to report rather than exploit', 'Bug bounties are required by smart contract auditors', 'Bug bounties improve protocol marketing'], correct: 1, explanation: 'Rational white-hat decision: report a $500M vulnerability for a $1M bounty (safe, legal) OR exploit it (criminal, risky). The bounty must exceed the risk-adjusted value of exploitation. For large protocols, $10M bounties for critical findings make economic sense — they cost 2-5% of what they protect against.' },
        { id: 'sec_exp_q3', question: 'How did Euler Finance recover most of the $197M stolen in their 2023 hack?', options: ['By reversing the blockchain via a hard fork', 'Through on-chain negotiation with the attacker — offering to retain a portion as a "bounty" while returning the rest. The attacker ultimately returned ~$177M, likely fearing legal consequences', 'By using chain-specific recovery tools built into Ethereum', 'Insurance paid out the full amount'], correct: 1, explanation: 'After the exploit, Euler\'s team sent on-chain messages to the attacker\'s address. They offered: keep 10% (~$20M) as bounty, return 90% (~$177M), no legal pursuit. The attacker eventually returned nearly all funds — presumably weighing the legal risk of holding identifiable stolen funds vs. a guaranteed bounty. On-chain negotiation has worked multiple times in DeFi history.' },
        { id: 'sec_exp_q4', question: 'What is MPC (Multi-Party Computation) in the context of institutional crypto custody?', options: ['A consensus algorithm for institutional blockchains', 'A cryptographic method where private key shares are distributed across multiple parties — no single party holds the complete key, requiring threshold approval for transactions, eliminating single-point-of-theft', 'A regulatory compliance framework for custodians', 'An algorithm for optimizing transaction fees'], correct: 1, explanation: 'Traditional wallets: one private key that can be stolen. MPC: the key is split into shares across multiple devices/parties. A 3-of-5 MPC means 3 parties must approve any transaction, and no party ever sees the full key. Used by Fireblocks ($3T+ in assets transacted), Fordefi, and other institutional platforms. Eliminates key theft attack vector.' },
        { id: 'sec_exp_q5', question: 'What is the recommended practice path for becoming a competitive smart contract security researcher?', options: ['Get a computer science degree then apply to audit firms', 'Ethernaut (basic) → Damn Vulnerable DeFi (complex DeFi attacks) → competitive audits on Code4rena/Sherlock → build verified findings portfolio → audit firm recruitment', 'Study only the Solidity documentation', 'Start by auditing production protocols immediately for experience'], correct: 1, explanation: 'The practice path mirrors software engineering: CTF challenges build foundational skills in a safe environment. Each CTF (Ethernaut, Damn Vulnerable DeFi, Paradigm CTF) builds progressively harder skills. Competitive audits translate skills to real code for real rewards while building a public, verified track record. Top researchers with Code4rena portfolios are actively recruited by audit firms.' },
      ],
    },
  ],
};

